//-------------------------------------------------------------------------
// 회계마감-"FI01" 체크 (마지막 마감 일자 체크) - 2012.06.20 추가
//-------------------------------------------------------------------------
scwin.f_checkCloseMonth = async function (currentYM) {
  console.log("=== f_checkCloseMonth (회계마감- FI01 체크 (마지막 마감 일자 체크))");
  if (scwin.vLoginCoCd == "") {
    scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
  }
  ds_commonCode.setEmptyValue();
  ds_closeMonthChk.setJSON([]);

  // ds_closeMonthChk.DataId = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC"
  //                                 + "&queryId=retrieveMaxCloseControlYearMonth"
  // 						        + "&param1=" + vLoginCoCd
  // 						        + "&param2=" + currentYM ;
  // ds_closeMonthChk.SyncLoad="true";
  // ds_closeMonthChk.Reset();

  // /src/main/resources/sqlmap/cm/zz/CommonEBC/commonPopUp.xml
  const strParam = {
    sysCd: "CommonEBC" // 시스템코드
    ,
    queryId: "retrieveMaxCloseControlYearMonth" // 쿼리ID
    ,
    param1: scwin.vLoginCoCd //
    ,
    param2: currentYM // 현재년월
  };

  //데이터셋에 정보설정
  ds_commonCode.setJSON(strParam);
  let e = await $c.sbm.execute($p, sbm_closeMonthChk);

  // console.log("▷ sbm_closeMonthChk_submitdone (회계마감- FI01 체크 (마지막 마감 일자 체크)) submitdone");

  if (e.responseJSON.resultDataSet[0].Code != 0) return;
  if (e.responseJSON.GAUCE) {
    ds_closeMonthChk.setJSON(e.responseJSON.GAUCE);
  }

  // 마감이후 첫월의 1일 : 계약의 해지 일 때 spplyDt 에 세팅
  scwin.mkSupplyDt = ds_closeMonthChk.getCellData(0, "col1") + "01";
  console.log("  mkSupplyDt (마감이후 첫월의 1일) [" + scwin.mkSupplyDt + "]");
};

