// 수정세금계산서 발행 권한을 공통코드에서 체크(FI090)
//-------------------------------------------------------------------------
scwin.f_getEditAuth = async function () {
  console.log("=== f_getEditAuth (수정세금계산서 발행 권한 체크 (FI090))");

  //공통코드 조회
  ds_code.set("grpCd", "FI090"); // 수정세금계산서발행권한
  ds_code.set("cd", scwin.acctDeptCd);
  ds_code.set("cdDesc", scwin.acctDeptNm);

  // tr_code.Post();

  var dcJSON = ds_code.getJSON();
  console.log("  *** ds_code : " + JSON.stringify(dcJSON));
  let e = await $c.sbm.execute($p, sbm_editAuth);

  // console.log("▷ sbm_editAuth_submitdone (수정세금계산서 발행 권한 FI090) submitdone");

  if (e.responseJSON.resultDataSet[0].Code != 0) return;
  if ($c.gus.cfIsNull($p, ds_editAuth.getCellData(0, "cd"))) {
    scwin.editAuth = "F";
  } else {
    scwin.editAuth = "T";
  }
  console.log("  -- editAuth : " + scwin.editAuth);
};

//-------------------------------------------------------------------------
// 신고옵션변경 권한 체크 (FI620)
//-------------------------------------------------------------------------
scwin.f_changeCheck = async function () {
  console.log("=== f_changeCheck (신고옵션변경 권한 체크 (FI620))");
  // ds_change.SyncLoad = true;
  // ds_change.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=FI628&cd=&cdNm=";
  // ds_change.Reset();

  let condition = "?grpCd=FI628&cd=&cdNm=";
  sbm_change.action = "/cm.zz.RetrieveCodeCMD.do" + condition;
  let e = await $c.sbm.execute($p, sbm_change);

  // console.log("▷ sbm_change_submitdone (신고옵션변경 권한) submitdone");

  if (e.responseJSON.resultDataSet[0].Code != 0) return;
  var empNo = scwin.userEmpNo;
  var count1 = 0;
  for (var i = 0; i < ds_change.getTotalRow(); i++) {
    partAdmin = ds_change.getCellData(i, "cd");
    if (empNo == partAdmin) {
      count1++;
    }
  }
  console.log("  count1 [" + count1 + "]");
  if (count1 > 0) {
    scwin.vAuth = "Y";
  } else {
    scwin.vAuth = "N";
  }
  if (scwin.vAuth == "Y") {
    // 전자세금계산서신고옵션코드 edit
    // gr_out.ColumnProp('documentfunccode','Edit')="any";
    gr_out.setReadOnly("column", "documentfunccode", false);
    console.log("==--== 신고옵션 edit");
  } else {
    // 전자세금계산서신고옵션코드 readOnly
    // gr_out.ColumnProp('documentfunccode','Edit')="none";
    gr_out.setReadOnly("column", "documentfunccode", true);
    console.log("==--== 신고옵션 readOnly");
  }
};

