scwin.f_Retrieve = async function () {
  console.log("====== f_Retrieve ==================");
  if (lc_qryConKnd.getValue() == "전표번호") {
    // if(!cfValidate([ed_slipNo])){
    // let rtn1 = await $c.gus.cfValidate([ed_slipNo]);

    if ($c.gus.cfIsNull($p, ed_slipNo.getValue())) {
      await $c.win.alert($p, $c.data.getMessage($p, MSG_CM_ERR_002, "전표번호"));
      ed_slipNo.focus();
      return;
    }
  } else if (lc_qryConKnd.getValue() == "공급일자") {
    if ($c.gus.cfIsNull($p, ed_spplyDtFrom.getValue())) {
      await $c.win.alert($p, "공급일자From은(는) 필수 입력 항목입니다.");
      ed_spplyDtFrom.focus();
      return;
    }
    if ($c.gus.cfIsNull($p, ed_spplyDtTo.getValue())) {
      await $c.win.alert($p, "공급일자To은(는) 필수 입력 항목입니다.");
      ed_spplyDtTo.focus();
      return;
    }

    // KYU_TEST : UDC 에서 검증
    // if(!cfValidateValue(ed_spplyDtFrom.text.trim().replace(" ",""), "date=YYYYMMDD")){
    //    await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
    //    ed_spplyDtFrom.focus();
    //    return;
    // }
    // if(!cfValidateValue(ed_spplyDtTo.text.trim().replace(" ",""), "date=YYYYMMDD")){
    //    await $c.win.alert("공급일자가 날자 형식에 맞지 않습니다.");
    //    ed_spplyDtTo.focus();
    //    return;
    // }
  }
  if ($c.gus.cfIsNull($p, ed_coCd.getValue())) {
    await $c.win.alert($p, "회사코드는 필수입니다.");
    ed_coCd.focus();
    return;
  }
  var dcJSON = ds_cond.getJSON();
  console.log("  *** ds_cond : " + JSON.stringify(dcJSON));

  // tr_retrieve.post();
  $c.sbm.execute($p, sbm_search);
};

