// 헤더 체크박스 클릭
//-------------------------------------------------------------------------
scwin.gr_out_onheaderclick = function (headerId) {
  console.log("----- gr_prov_onheaderclick (헤더 체크박스 클릭)");

  // <script language="javascript"  for=gr_out event=OnHeadCheckClick(Col,Colid,bCheck)>
  var CountRow = ds_out.getTotalRow();
  var i = 0;
  if (headerId == "chk") {
    var bCheck = gr_out.getHeaderValue("chk");
    console.log("---  bCheck : " + bCheck);
    if (bCheck) {
      for (var i = 0; i < CountRow; i++) {
        // console.log("  ["+i+"] delEnableYn ["+ds_out.getCellData(i,"delEnableYn")+"]  responsetype ["+ds_out.getCellData(i,"responsetype")+"]");

        if (ds_out.getCellData(i, "delEnableYn") != "F" && (ds_out.getCellData(i, "responsetype") != "N" || $c.gus.cfIsNull($p, ds_out.getCellData(i, "responsetype")))) {
          ds_out.setCellData(i, "chk", "1");
        } else {
          // console.log("--- 거래처전송 불가능");
          ds_out.setCellData(i, "chk", "0");
        }
      }
    } else {
      // for(var i=1;i<=ds_out.CountRow;i++){
      for (var i = 0; i < CountRow; i++) {
        ds_out.setCellData(i, "chk", "0");
      }
    }
  }
};

//-------------------------------------------------------------------------
// 그리드 셀클릭
//    - 전표번호 팝업
//    - 돋보기 버튼 컨트롤 (email)
//-------------------------------------------------------------------------
scwin.gr_out_oncellclick = async function (rowIndex, columnIndex, columnId) {
  console.log("----- gr_out_oncellclick (" + rowIndex + ",  " + columnIndex + ",  " + columnId + ")");
  var Row = rowIndex;
  var Colid = columnId;
  if (ds_out.getCellData(Row, "delEnableYn") == "T") {
    // 삭제가능여부
    if (ds_out.getCellData(Row, "responsetype") != "F") {
      // 응답여부 != F
      // gr_out.ColumnProp("chk","Edit") = true;
      // gr_out.ColumnProp("modRsnCd","Edit") = false;

      gr_out.setCellReadOnly("chk", false); // 체크 edit
      gr_out.setCellReadOnly("modRsnCd", true); // 수정사유코드 readOnly

      console.log("==--== 체크 edit, 수정사유코드 readOnly");
    } else if (ds_out.getCellData(Row, "responsetype") == "F") {
      // 응답여부 == F
      if (scwin.editAuth == "T") {
        // gr_out.ColumnProp("chk","Edit") = true;
        // gr_out.ColumnProp("modRsnCd","Edit") = true;

        gr_out.setCellReadOnly("chk", false); // 체크 edit
        gr_out.setCellReadOnly("modRsnCd", false); // 수정사유코드 edit

        console.log("==--== 체크 edit, 수정사유코드 edit");
      }
    }
  } else {
    // gr_out.ColumnProp("chk","Edit") = false;
    // gr_out.ColumnProp("modRsnCd","Edit") = false;

    gr_out.setCellReadOnly("chk", true); // 체크 readOnly
    gr_out.setCellReadOnly("modRsnCd", true); // 수정사유코드 readOnly

    console.log("==--== 체크 readOnly, 수정사유코드 readOnly");
  }
  if (Row >= 0) {
    console.log("  ----- ----- Row >= 0 (건수가 있을 때...)");
    if (Colid == "slipNo") {
      if (!$c.gus.cfIsNull($p, ds_out.getCellData(Row, "slipNo"))) {
        await $c.gus.cfShowSlipInfo($p, ds_out.getCellData(Row, "slipNo"));
      }
    }
    // 역분개전표 : 없슴
    else if (Colid == "reverseSlipNo") {
      if (!$c.gus.cfIsNull($p, ds_out.getCellData(Row, "reverseSlipNo"))) {
        $c.gus.cfShowSlipInfo($p, ds_out.getCellData(Row, "reverseSlipNo"));
      }
    } else if (Colid == "chk") {
      if (ds_out.getCellData(Row, "delEnableYn") == "T") {
        if (ds_out.getCellData(Row, "responsetype") != "F") {
          // gr_out.ColumnProp("chk","Edit") = true;
          // gr_out.ColumnProp("modRsnCd","Edit") = false;

          gr_out.setCellReadOnly("chk", false); // 체크 edit
          gr_out.setCellReadOnly("modRsnCd", true); // 수정사유코드 readOnly

          console.log("==--== 체크 edit, 수정사유코드 readOnly");
        } else if (ds_out.getCellData(Row, "responsetype") == "F") {
          if (scwin.editAuth == "T") {
            // gr_out.ColumnProp("chk","Edit") = true;
            // gr_out.ColumnProp("modRsnCd","Edit") = true;

            gr_out.setCellReadOnly("chk", false); // 체크 edit
            gr_out.setCellReadOnly("modRsnCd", false); // 수정사유코드 edit

            console.log("==--== 체크 edit, 수정사유코드 edit");
          }
        }
      } else {
        await $c.win.alert($p, "거래처 전송이 불가능한 건 입니다.");

        // 해당 DataSet의 Row를 원래값(=OriginalData)로 복원시킨다.
        // 지정한 GridView에 선택컬럼(chk)이 체크된 Row들을 취소(Undo) 처리한다.
        // ds_out.Undo(Row);  
        $c.data.undoRow($p, ds_out, "Y"); // 두번째 파라미터가 "undefined" 가 아닐 때 해당되는 row 의 체크박스만 해제. 체크박스 컬럼의 id 를 chk 로 맞춰야 함

        return false;

        // KYU_TEST : 도달하지 못하는 코딩
        // gr_out.ColumnProp("chk","Edit") = false;
        // gr_out.ColumnProp("modRsnCd","Edit") = false;

        gr_out.setCellReadOnly("chk", true); // 체크 readOnly
        gr_out.setCellReadOnly("modRsnCd", true); // 수정사유코드 readOnly

        console.log("==--== 체크 readOnly, 수정사유코드 readOnly");
      }
    } else if (Colid == "spplyDt") {
      // 수정사유가 [계약의 해지]일 경우만 공급일자 수정가능 - 2012.06.20 추가
      if (ds_out.getCellData(Row, "modRsnCd") == "04") {
        // 수정사유 - 01: 기재사항 착오정정, 03: 환입, 04: 계약의 해제
        // gr_out.ColumnProp("spplyDt","Edit")= "Numeric";
        gr_out.setCellReadOnly("spplyDt", false); // 수정일자 readOnly

        console.log("==--== 수정일자 edit (Numeric)");
      } else {
        // gr_out.ColumnProp("spplyDt","Edit")= "None";
        gr_out.setCellReadOnly("spplyDt", true); // 체크 readOnly

        console.log("==--== 수정일자 readOnly");
      }
    }
    // KYU_NEW : email 그리드 팝업
    // else if ( Colid == "email" ) {
    //     console.log("  ----- email 그리드 팝업");

    // language=JavaScript for=gr_out event=OnPopup(row,colid,data)>
    //     if(colid=="email"){
    //         f_openPopUp('3','F');  // 그리드 팝업
    //     }

    // let retText = {inputType : "text"};
    // let retTextImage= {inputType : "textImage", options : {imageClickFunction:"scwin.gr_out_ontextimageclick(rowIndex, columnIndex)"} };

    // if ( ds_out.getColumnID(columnIndex) == "email" )  {
    //     gr_out.setCellInputType(rowIndex, "email", retTextImage);

    //     scwin.gr_out_ontextimageclick(rowIndex, columnIndex);
    // }
    // }
  }
};

