//-------------------------------------------------------------------------
scwin.ds_out_oncelldatachange = function (info) {
  //tobe 소스
  let colid = info.colID;
  let row = info.rowIndex;
  // <!-- 수정사유가 [계약의 해지]로 변경시 마감이후 달의 1일자로  공급일자 자동셋팅 --> <!-- 2012.06.20 추가 --> 
  // <language=JavaScript for=ds_out event=OnColumnChanged(row,colid)>
  if (colid == "modRsnCd") {
    if (ds_out.getCellData(row, "modRsnCd") == "04") {
      // spplyDt		
      ds_out.setCellData(row, "spplyDt", scwin.mkSupplyDt);
      console.log("  [" + row + "]  수정사유가 [계약의 해지]로 변경시 마감이후 달의 1일자로  공급일자 자동셋팅 : spplyDt [" + ds_out.getCellData(row, "spplyDt") + "]");
    } else {
      ds_out.setCellData(row, "spplyDt", ds_out.getCellData(row, "orgSpplyDt"));
    }
  }
};

