//-------------------------------------------------------------------------
// 거래처 전송
//-------------------------------------------------------------------------
scwin.f_Send = async function (e) {
  console.log("=== f_Send (거래처 전송))");

  //  if(ds_out.IsUpdated == false){
  if (ds_out.getModifiedIndex().length == 0) {
    await $c.win.alert($p, "변경된 내역이 없습니다.");
    return;
  }

  // if(scwin.f_chkSend()){
  let rtn1 = await scwin.f_chkSend();
  if (rtn1)
    // KYU_TEST : true 이면 중단
    return;
  var count = 0;

  // KYU_ORDER : 준비 단계로 이동  ds_admin --> ds_admin2
  // 수정세금계산서발행 (국세청최종신고 삭제전송) 권한 조회
  // ds_admin.SyncLoad = true;
  // ds_admin.DataID = "/cm.zz.RetrieveCodeCMD.do?grpCd=FI090&cd=&cdNm=";
  // ds_admin.Reset();

  // 수정세금계산서발행 (국세청최종신고 삭제전송) 권한 체크 (FI090)
  await scwin.f_changeCheck2();
  var admin = "";
  for (var i = 0; i < ds_admin.getTotalRow(); i++) {
    admin = ds_admin.getCellData(i, "cd");

    // admin  00009: 재경, 00691: 동원로엑스광양(광양), 00692: 동원로엑스광양(복합), 00694: 대성냉동, 00695: 대성TLS, 00698: 인천북항(타법인), 00966: 동원TLS, 01047: BIDC 관리팀

    // if(vDeptCd == admin || vEmpNo == "091610" || vEmpNo == "140283" || vEmpNo == "130194" || vEmpNo == "230836" || vEmpNo == "131742" || vEmpNo == "081607" || vEmpNo == "208014"){
    if (scwin.acctDeptCd == admin || scwin.userEmpNo == "091610" || scwin.userEmpNo == "140283" || scwin.userEmpNo == "130194" || scwin.userEmpNo == "230836" || scwin.userEmpNo == "131742" || scwin.userEmpNo == "081607" || scwin.userEmpNo == "208014") {
      count++;
    }
  }
  if (count == '0') {
    //alert("재경팀 아님");
    for (i = 0; i < ds_out.getTotalRow(); i++) {
      if (ds_out.getCellData(i, "chk") == 1) {
        if (ds_out.getCellData(i, "responsetype") == 'F') {
          await $c.win.alert($p, "선택한 " + i + "번째행의 계산서는 응답결과가 국세청 최종접수 단계 입니다.\n\n" + "국세청 최종접수 상태인 경우 재경팀 및 자회사 담당자만 전송 가능 합니다.\n\n" + "재경팀에 문의 하시기 바랍니다.");

          // 해당 DataSet의 Row를 원래값(=OriginalData)로 복원시킨다.
          // 지정한 GridView에 선택컬럼(chk)이 체크된 Row들을 취소(Undo) 처리한다.
          // ds_out.Undo(i);  
          $c.data.undoRow($p, ds_out, "Y"); // 두번째 파라미터가 "undefined" 가 아닐 때 해당되는 row 의 체크박스만 해제. 체크박스 컬럼의 id 를 chk 로 맞춰야 함

          return false;
        }
      }
    } // end of for
  }

  // 회사코드Temp 세팅
  ds_out.setCellData(ds_out.getRowPosition(), "coCdTemp", ed_coCd.getValue());

  // if (cfConfirmMsg("선택하신 부가세를 거래처전송을 하시겠습니까?")) {
  let rtn2 = await $c.win.confirm($p, "선택하신 부가세를 거래처전송을 하시겠습니까?");
  if (rtn2) {
    // tr_send.post();
    await $c.sbm.execute($p, sbm_send);
  }
};

