//-------------------------------------------------------------------------
// 전송전 체크
//   retVal = true 이면 전송안함
//-------------------------------------------------------------------------
scwin.f_chkSend = async function () {
  console.log("    === f_chkSend (전송전 체크))");
  var retVal = false;
  var chkCnt = 0;
  for (var i = 0; i < ds_out.getTotalRow(); i++) {
    // if(ds_out.NameValue(i,"chk")==1){
    if (ds_out.getCellData(i, "chk") == "1") {
      chkCnt++;
      if (ds_out.getCellData(i, "email") == "") {
        await $c.win.alert($p, "email이 없습니다.");
        //    gr_out.SetColumn("email");
        ds_out.setRowPosition(i);
        gr_out.setFocusedCell(i, "email", true);
        retVal = true;
        break;
      }
      if (ds_out.getCellData(i, "delEnableYn") == "F") {
        await $c.win.alert($p, "거래처 전송을 할 수 없는 내역이 선택되어 있습니다.");
        // gr_out.SetColumn("chk");
        ds_out.setRowPosition(i);
        gr_out.setFocusedCell(i, "chk", true);
        retVal = true;
        break;
      }
      if (ds_out.getCellData(i, "delEnableYn") == "T" && ds_out.getCellData(i, "responsetype") == "F") {
        if (ds_out.getCellData(i, "modRsnCd") == "") {
          await $c.win.alert($p, "수정세금계산서를 보낼때는 수정사유는 필수입니다.");
          // gr_out.SetColumn("modRsnCd");
          ds_out.setRowPosition(i);
          gr_out.setFocusedCell(i, "modRsnCd", true);
          retVal = true;
          break;
        }
      }
    }
  }
  if (chkCnt == 0) {
    await $c.win.alert($p, "선택한 부가세가 없습니다.");
    retVal = true;
  }
  return retVal;
  ;
};

